B.a1j=new A.bk(2,"Serie Num\xe9rica",'Cada n\xfamero se multiplica por 2 en su columna. \xbfQu\xe9 n\xfamero falta en la casilla con "?"?',"assets/figuras_psicometrico/serie/q02_secuencia.svg",B.Wa,"C","Patr\xf3n: cada valor se multiplica x2 por columna. Fila 3, columna 3: 5 x 4 = 20. La respuesta correcta es 20.","serie")
