B.a1k=new A.bk(6,"Simetr\xeda y Reflexi\xf3n","Identifica cu\xe1l de las opciones representa el reflejo exacto de la figura original en el espejo.","assets/figuras_psicometrico/simetria/q06_secuencia.svg",B.W2,"B","Al reflejar una imagen horizontalmente, los elementos a la derecha pasan a la izquierda y viceversa. El tri\xe1ngulo y el c\xedrculo cambian de posici\xf3n relativa horizontalmente, como se ve en la opci\xf3n B.","simetria")
B.Wc=new A.aP(B.U,["assets/figuras_psicometrico/serie/q07_opcion_a.svg","assets/figuras_psicometrico/serie/q07_opcion_b.svg","assets/figuras_psicometrico/serie/q07_opcion_c.svg","assets/figuras_psicometrico/serie/q07_opcion_d.svg","assets/figuras_psicometrico/serie/q07_opcion_e.svg"],t.l)
B.a1h=new A.bk(7,"Secuencia Din\xe1mica","Observa el movimiento de los puntos y el tama\xf1o del c\xedrculo central. \xbfQu\xe9 figura sigue?","assets/figuras_psicometrico/serie/q07_secuencia.svg",B.Wc,"B","La secuencia repite un ciclo de 4 estados. El sexto elemento corresponde al segundo estado del ciclo (Estado B).","serie")
