B.a1T=new A.bk(54,"Cerillos: La Nada","Corrige 5 - 5 = 5 moviendo un cerillo.","assets/figuras_psicometrico/cerillos/cerillo_12.svg",B.az,"D",'Convierte el "-" en "+" y el segundo 5 en 0. 5 + 0 = 5.',"logica")
